mapper.select:
SELECT ak.id, ak.user_id, u.username, ak.config_id, arc.name as config_name, ak.knowledge_base_id, kb.name as knowledge_base_name, ak.key_name, ak.api_key, ak.expire_time, ak.status, ak.deleted, ak.create_time, ak.update_time FROM api_key ak LEFT JOIN sys_user u ON ak.user_id = u.id LEFT JOIN api_relay_config arc ON ak.config_id = arc.id LEFT JOIN knowledge_base kb ON ak.knowledge_base_id = kb.id WHERE ak.deleted = 0
AND ak.user_id = #{userId}
ORDER BY ak.create_time DESC
